mapper.select:
SELECT market_type
FROM stock_master
WHERE stock_code = #{stockCode}

mapper.insert:
INSERT INTO user_watchlist (user_seq, stock_seq)
VALUES (
           #{userSeq},
           (
               SELECT stock_seq
               FROM stock_master
               WHERE stock_code = #{stockCode}
           )
       )

mapper.delete:
DELETE FROM user_watchlist
WHERE user_seq = #{userSeq}
  AND stock_seq = (
    SELECT stock_seq
    FROM stock_master
    WHERE stock_code = #{stockCode}
)

mapper.select:
SELECT count(*)>0
FROM user_watchlist join stock_master on user_watchlist.stock_seq = stock_master.stock_seq
WHERE user_seq = #{userSeq} AND stock_code=#{stockCode}
